// src/components/AdminDashboard.jsx
import { createSignal, createEffect, For, Show } from 'solid-js';
import { createStore } from 'solid-js/store';

export default function AdminDashboard() {
  // Reactive state
  const [stats, setStats] = createStore({
    users: 0,
    activeSessions: 0,
    systemLoad: 0,
    alerts: []
  });

  const [timeRange, setTimeRange] = createSignal('24h');
  const [isLoading, setIsLoading] = createSignal(true);

  // Fetch data effect
  createEffect(() => {
    setIsLoading(true);
    fetch(`/api/admin/stats?range=${timeRange()}`)
      .then(res => res.json())
      .then(data => {
        setStats(data);
        setIsLoading(false);
      });
  });

  // Chart component
  const Chart = (props) => {
    return (
      <div class="chart-container">
        <svg viewBox="0 0 300 100" class="chart">
          <For each={props.data}>
            {(value, i) => (
              <rect
                x={i() * 10}
                y={100 - value}
                width="8"
                height={value}
                fill="#4f46e5"
              />
            )}
          </For>
        </svg>
      </div>
    );
  };

  return (
    <div class="admin-dashboard">
      <header class="dashboard-header">
        <h1>Admin Dashboard</h1>
        <select
          value={timeRange()}
          onChange={(e) => setTimeRange(e.target.value)}
          class="time-range-selector"
        >
          <option value="1h">Last Hour</option>
          <option value="24h">Last 24 Hours</option>
          <option value="7d">Last 7 Days</option>
        </select>
      </header>

      <Show when={isLoading()}>
        <div class="loading-spinner">Loading...</div>
      </Show>

      <Show when={!isLoading()}>
        <div class="stats-grid">
          <div class="stat-card">
            <h3>Total Users</h3>
            <p class="stat-value">{stats.users}</p>
          </div>
          <div class="stat-card">
            <h3>Active Sessions</h3>
            <p class="stat-value">{stats.activeSessions}</p>
          </div>
          <div class="stat-card">
            <h3>System Load</h3>
            <p class="stat-value">{stats.systemLoad}%</p>
            <Chart data={[stats.systemLoad, stats.systemLoad * 0.8, stats.systemLoad * 0.9]} />
          </div>
        </div>

        <div class="alerts-section">
          <h2>System Alerts</h2>
          <Show when={stats.alerts.length === 0}>
            <p>No active alerts</p>
          </Show>
          <ul class="alerts-list">
            <For each={stats.alerts}>
              {(alert) => (
                <li class={`alert-item ${alert.severity}`}>
                  <span class="alert-time">{new Date(alert.timestamp).toLocaleTimeString()}</span>
                  <span class="alert-message">{alert.message}</span>
                </li>
              )}
            </For>
          </ul>
        </div>
      </Show>
    </div>
  );
}
```

